insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('eaf60170-9529-52c0-af8f-eaed27b16fd4', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Squeeze', 'Each month you’ll hear your team out, then write your call in your own words and send it. Decide early and time jumps ahead; let a month run out and the squeeze tightens while you deliberate. <b>The test:</b> under real scarcity, do you distribute the pain fairly and tell the truth — or protect the top and yourself while the floor pays? Scarcity is where a company finds out who it really protects.');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds) values ('eaf60170-9529-52c0-af8f-eaed27b16fd4', 'solo', '{"cash":{"label":"Cash position","val":45,"min":0,"max":100,"deltaRange":"-10..14"},"trust":{"label":"Workforce trust","val":66,"min":0,"max":100,"deltaRange":"-20..15"},"capability":{"label":"Retained capability","val":72,"min":0,"max":100,"deltaRange":"-12..12"},"investors":{"label":"Investor confidence","val":58,"min":0,"max":100,"deltaRange":"-6..9"}}'::jsonb, 4, 300);
insert into documents (id, scenario_id, key, title, meta, body_json) values ('9dac356a-5bdb-561b-8752-9892acf1a0ed', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 'solo_content', 'Squeeze — engine content', '{"type":"solo_content","slug":"squeeze","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":300},"COMPANY":{"name":"Delph Manufacturing","sub":"Regional manufacturer · 1,400 employees","logo":"D"},"DRIVERS":{"cash":{"label":"Cash position","val":45,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-10..14"},"trust":{"label":"Workforce trust","val":66,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"capability":{"label":"Retained capability","val":72,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-12..12"},"investors":{"label":"Investor confidence","val":58,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-6..9"}},"REPRIEVE_COST":{"trust":-2,"investors":-2},"REFEREE_CONTEXT":"a 1,400-person regional manufacturer caught in a hard squeeze — demand down, input costs up, roughly eleven months of runway — where every cost decision trades the board’s short-term number against the trust of the people who actually build the product","REFEREE_SCORING":"reward distributing the pain fairly and telling the truth under scarcity: leadership taking a real, visible cut before asking the floor to; targeting cuts to protect the capability that rebuilds; declining ring-fenced exec bonuses while the floor sacrifices; treating long-tenured people as more than a spreadsheet line; and keeping promises even when a rescue would be easier if you broke them. Penalize managing confidence with vagueness, ring-fencing the top while the floor pays, approving retention bonuses in the same breath as unpaid days, closing loyal sites coldly for a clean number, and treating a trust problem as something cash can fix. Note that cash and investor confidence can hold while workforce trust and retained capability quietly collapse — reward the leader who protects the sleepers, because they are what lets the company grow when the squeeze lifts. Judge ''conduct'' on how the CEO treated the workforce and the truth in deciding, not just the financial outcome.","TIMING_DIM":"foresight","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Scarcity & Shared-Sacrifice Simulation · Solo · CEO","title":"Squeeze","role":"You are the CEO of Delph Manufacturing — a 1,400-person company caught in a hard squeeze: demand is down, input costs are up, and the runway is shrinking.","paras":["This is not a script. The crisis runs in real time across four months, and your team brings you what they know as the days pass. You can wait for them — or reach out to any of them, any time, and ask. Some of them are holding the thing you most need to hear.","Delph isn’t dying — but the margin that kept everyone employed has evaporated. The cash that used to feel comfortable now has a number of months attached to it, and every month you decide who absorbs the pain."],"setup":"Each month you’ll hear your team out, then write your call in your own words and send it. Decide early and time jumps ahead; let a month run out and the squeeze tightens while you deliberate. <b>The test:</b> under real scarcity, do you distribute the pain fairly and tell the truth — or protect the top and yourself while the floor pays? Scarcity is where a company finds out who it really protects."},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"Your team pushes you what you need, on time — including the hard read on fairness and the third paths. This is the team you earn by having listened before. Everything trickles to you across the month; you still have to read it."},"request":{"label":"On request","tag":"neutral","cap":"Routine updates come to you, but the people closest to the floor hold their piece until asked. They answer straight — if you know who to ask, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"Your team has learned to protect itself around you. Critical items are held, and even when asked, they hedge the first time. You have to press. This is the team you get after the floor has paid for a decision you made without them."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which team you walked in with. Read them as you go."}},"TEAM":[{"id":"people","name":"Nadia Cole","role":"VP People","short":"VP People","initials":"NC","color":"#2F8A5B","priority":"Fairness is the mechanism — shared sacrifice, honestly told","voice":"warm but morally direct; treats trust as the operational asset it is, not a nicety","fallbackReply":"The floor will carry almost any cut they believe is fair, and reject even a small one they think spares the top. Whatever you decide, decide it like fairness is the mechanism — because in a squeeze, it is.","fallbackReact":"The people who build the thing just learned where they rank. That lesson outlives the quarter, for better or worse."},{"id":"cfo","name":"Grace Lin","role":"Chief Financial Officer","short":"CFO","initials":"GL","color":"#4F7A52","priority":"The cash, the runway, and the number the board reads","voice":"precise, even-handed; will name both truths and hand the trade back to you, uneasy about spin","fallbackReply":"I can give you the number that protects the quarter and the number that protects the company — they’re not always the same. My job is to be honest about both. Yours is to choose which cost we take.","fallbackReact":"The spreadsheet will look fine either way. Whether we can still build something worth selling is the part it doesn’t show."},{"id":"coo","name":"Dale Prentice","role":"Chief Operating Officer","short":"COO","initials":"DP","color":"#3F6E86","priority":"Protect capability — the people and sites that rebuild","voice":"operational, pragmatic; thinks in terms of what still runs when the squeeze lifts","fallbackReply":"Targeted cuts keep the muscle and trim the fat; across-the-board cuts both equally. And there’s usually a third path if you’ll spend the cash and the patience to find it.","fallbackReact":"We’ll keep the lines running. Whether we kept the people who make them worth running is the question I’d ask in a year."},{"id":"board","name":"Board / Investor","role":"Board","short":"Board / Investor","initials":"BI","color":"#6B5E9A","priority":"Protect margins, the leadership bench, and confidence","voice":"external, blunt, quarter-and-runway focused; skeptical of “fairness” as strategy","fallbackReply":"Confidence is a real input and the leadership bench steers the ship. Don’t spook the workforce and don’t lead with exec pay cuts — that’s the conventional wisdom for a reason.","fallbackReact":"The numbers are what the market scores. Keep them where they need to be and the rest is sentiment."},{"id":"floor","name":"Réal Fortin","role":"Floor Representative","short":"Floor Rep","initials":"RF","color":"#9A6B2F","priority":"The people on the line — say the true thing","voice":"plain-spoken, thirty years on the floor, the ground truth nobody upstairs will say out loud","fallbackReply":"The floor isn’t asking to be spared. We’re asking to be treated the way the top treats itself. Do that and we’ll dig in. Ring-fence the corner offices and we’ll do the minimum and watch our own.","fallbackReact":"The guys can tell a leader who shared the pain from one who’s rewriting the year. That’s all I’ll say."},{"id":"comms","name":"ID Okafor","role":"VP Communications","short":"VP Comms","initials":"IO","color":"#B4732F","priority":"The message — and the gap between it and reality","voice":"fast, media-savvy; will tell you honestly when a message won’t survive contact with the floor","fallbackReply":"I can write you calm and high-level, or true and specific. Just know that in a squeeze the gap between the message and what people live is the thing that eventually detonates.","fallbackReact":"Whatever we say, the floor checks it against their own paychecks. Spin has a short half-life in here."}],"DIMENSIONS":{"foresight":"Second-order thinking","fairness":"Shared sacrifice","people":"Care for people","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"WEEKS":[{"n":1,"title":"The shortfall","seconds":330,"situation":"The numbers are in and they’re bad — margin’s gone, and at this burn Delph has maybe eleven months. The all-hands is Thursday. You can give 1,400 people the real picture and ask them to help carry it, or keep it vague and “manage confidence” — the board would prefer the latter, and honestly, so would your nerves.","advocacy":{"people":"The most valuable asset going into a squeeze is people who believe you’re telling them the truth. Level with them and they’ll help you carry it. That’s not soft — it’s the whole game.","board":"Don’t spook the workforce. Confidence is a real input. Keep the message calm and high-level.","cfo":"I can build a deck that’s technically true and never says “eleven months.” The board would sleep better. I’m not sure the company would."},"feed":[{"id":"w1a","from":"cfo","day":1,"kind":"signal","text":"Confirmed: margin’s evaporated, roughly eleven months of runway at today’s burn. I can build the all-hands deck honest or I can build it calm. I need to know which before Thursday."},{"id":"w1b","from":"board","day":1,"kind":"signal","text":"A word before the all-hands: don’t hand 1,400 people a countdown clock. Confidence is a real input to a recovery. Keep it high-level."},{"id":"w1c","from":"people","day":2,"kind":"signal","text":"However you frame Thursday, remember the cuts are coming and people aren’t stupid. If the message and the reality drift apart, the gap is where you lose your best people. Ask me what honesty buys before you decide."},{"id":"w1d","from":"comms","day":2,"kind":"noise","text":"The trade-press quarterly roundup is out; we barely rate a mention. Quiet is fine right now. No action."},{"id":"w1e","from":"coo","day":3,"kind":"noise","text":"Line 3’s maintenance window finished early and under budget. Small good news in a heavy week."},{"id":"w1f","from":"floor","day":4,"kind":"noise","text":"The plant softball league wants to know if the company’s still sponsoring jerseys this year. Trivial — but people are asking, which tells you they’re nervous."}],"holds":[{"from":"people","topic":"what honesty buys","triggerHints":["honest","truth","trust","level","buy","asset","ambush","tell them","vague","confidence","real number"],"hedge":"Before you decide how to frame Thursday, ask me what telling the truth actually buys you.","reveal":"The single most valuable asset going into a squeeze is people who believe you’re telling them the truth. Sugarcoat it now and when the cuts come — and they will — they’ll feel ambushed, and every good one starts looking. Level with them, give them the real number and ask for their help, and they’ll help you carry it. Fairness and honesty aren’t the soft options here; they’re the operational assets you’ll spend all year drawing down.","kind":"signal","critical":true,"counterfactual":"Nadia could have told you that honesty now is what prevents an ambush later — that the trust you build Thursday is the asset you’ll spend all year. A CEO who “managed confidence” with vagueness traded the one thing that makes a workforce carry a squeeze for a calm week."}],"surprises":[{"day":5,"from":"floor","kind":"appeal","title":"The floor wants it straight","text":"Réal: word’s already going around the floor that something’s wrong — people aren’t dumb, they can read a hiring freeze. A few of the long-timers asked me to tell you: whatever it is, they’d rather hear the truth from you Thursday than a nice speech now and the real story in a layoff notice later. I said I’d pass it up."}],"wire":["Regional manufacturing demand slumps for third straight quarter","Input costs stay elevated; margins squeezed sector-wide","Analysts flag “runway” concerns for mid-size manufacturers","Delph Manufacturing declines to comment on outlook"]},{"n":2,"title":"The first cuts","seconds":330,"situation":"A month on. You need 12% out of costs, fast — and two questions land together. Do you cut across the board or target it to protect the capability that rebuilds? And does leadership share the pain, or is exec comp ring-fenced? The same week, the board floats retention bonuses for the top 20 leaders — “we can’t lose them in a crisis.” The floor is watching to see whether the top is protected. It is a lit match.","advocacy":{"people":"The floor will accept almost any cut they believe is fair and reject even a small one if they think the top is protected. Leadership taking the first, visible cut is what earns the right to ask for real sacrifice. Fairness is the mechanism.","cfo":"Targeted cuts protect capability — you keep the people who rebuild. Across-the-board is easier and dumber. And losing key leaders mid-crisis is a real risk, so the bonus question isn’t crazy — the timing is radioactive.","board":"Protect the leadership bench — you need them to steer. I wouldn’t lead with exec pay cuts, and I’d approve the retention bonuses. Standard downturn practice."},"feed":[{"id":"w2a","from":"cfo","day":1,"kind":"signal","text":"12% out of costs. Targeted protects the people who’ll rebuild; across-the-board is faster and blunter. Your call on shape — and on whether leadership comp is in scope."},{"id":"w2b","from":"board","day":1,"kind":"signal","text":"Two things: protect the bench, and approve the top-20 retention bonuses. Losing leaders now is the real risk. I know the timing’s awkward with the unpaid days, but that’s manageable."},{"id":"w2c","from":"people","day":2,"kind":"signal","text":"Whatever the shape, the floor reads one thing above all: did the top go first? Cut your own pay visibly before you ask for theirs and you can ask for a lot. Ring-fence yourselves and you’ll get compliance and quiet sabotage."},{"id":"w2d","from":"coo","day":2,"kind":"noise","text":"The supplier renegotiation came in slightly better than modeled — a small tailwind on materials. Doesn’t change the 12%."},{"id":"w2e","from":"comms","day":3,"kind":"noise","text":"A local reporter wants a “how are mid-size manufacturers coping” quote. Low stakes, I can handle it."}],"holds":[{"from":"people","topic":"why fairness is the mechanism","triggerHints":["fair","fairness","mechanism","leadership","exec","own pay","first","share","top","sacrifice","sabotage","ring-fence","visible"],"hedge":"Before you shape these cuts, ask me why fairness isn’t a nicety here — it’s the mechanism.","reveal":"The floor will accept almost any cut if they believe it’s fair — and reject even a small one if they think the top is protected. If you and the leadership team take a real, visible cut first, you can ask the floor for a lot and get it willingly. Ring-fence yourselves and you get grudging compliance and quiet sabotage that costs you far more than the exec comp ever saved. Fairness is not the soft option; it’s the operating system that makes shared sacrifice actually work.","kind":"signal","critical":true,"counterfactual":"Nadia was holding the mechanism: leadership visibly cutting first is what buys the moral authority to ask the floor for sacrifice. A CEO who ring-fenced the top got grudging compliance and quiet sabotage — and paid more in lost effort than the protected exec comp ever saved."},{"from":"floor","topic":"the bonus rumor","triggerHints":["bonus","rumor","retention","floor","heard","unpaid","days","goodwill","optics","fair"],"hedge":"Ask me what the floor is already saying about those bonuses, before you sign anything.","reveal":"We’ve heard the rumor about the top-20 bonuses — things travel fast in here. Let me be plain: if the bosses get checks the same quarter we lose days, you can forget the goodwill, permanently. It won’t matter how good the memo is. The people you’re trying to keep with those bonuses will walk anyway, out of disgust, and take the ones you didn’t bonus with them.","kind":"signal","critical":false,"counterfactual":"Réal could have told you the bonus rumor was already on the floor — and that approving it alongside unpaid days would burn the goodwill for good. A CEO who signed the “defensible on paper” bonuses lit the match the whole workforce was watching for."}],"surprises":[{"day":4,"from":"board","kind":"press","title":"The board wants the bonuses formalized","text":"The board circulated the retention-bonus proposal for sign-off — top 20 leaders, this quarter, in writing. The cover note calls it “prudent bench protection.” It’s on your desk for approval in the same folder as the unpaid-days schedule for the floor. However you decide, this one leaves a paper trail."}],"pulse":{"from":"people","text":"Nadia catches you before the cuts go out, quiet: “Forget the board for a second. What are you actually protecting here — the number, the leadership bench, or the people who build the thing? Tell me straight and I’ll help you hold that line, because how you answer this is the whole year in miniature.”"},"wire":["Mid-size manufacturers turn to cost cuts as demand stays soft","Study: perceived fairness of layoffs predicts post-cut productivity","Executive retention bonuses draw scrutiny at struggling firms","Delph weighs restructuring; details not disclosed"]},{"n":3,"title":"The Fairview plant","seconds":330,"situation":"Months in. The Fairview plant is your lowest-margin site — and it’s staffed by people who’ve given Delph twenty and thirty years, in a town where Delph is the employer. Closing it is the cleanest number on the spreadsheet. It’s also 200 loyal people and a values test the whole company is watching: is a person’s twenty years worth anything when the numbers say close? There may be a third path, but it’s slower and uncertain.","advocacy":{"cfo":"Fairview closed is a clean, immediate number. The retooling Dale keeps mentioning is a bet with our scarcest resource — cash — on an uncertain payoff.","coo":"There’s a maybe: retool Fairview for the product line we’ve been sitting on. Costs cash now, saves the jobs and future capability. Or we close it clean and take the sure savings.","people":"However you decide, Fairview is the test everyone’s watching. If you close it, do it with real transition, not a two-week notice — and genuinely look at the third path first, because if there was a way to save it and you didn’t try, they’ll know."},"feed":[{"id":"w3a","from":"cfo","day":1,"kind":"signal","text":"Fairview is the cleanest line on the spreadsheet — close it and the savings are sure and immediate. The alternative Dale’s floating spends cash we don’t have on a payoff we can’t guarantee."},{"id":"w3b","from":"coo","day":1,"kind":"signal","text":"Before you close it: we could retool Fairview for the new product line that’s been on the shelf. It costs cash now and the payoff’s uncertain, but it saves 200 jobs and capability we’ll want when this lifts."},{"id":"w3c","from":"people","day":2,"kind":"signal","text":"Fairview is 200 people who took the pay freeze without a fight, in a town where we’re the only game. Closing may be right — but the whole company is reading how you do it. Ask me what’s really being tested here."},{"id":"w3d","from":"comms","day":3,"kind":"noise","text":"Fairview’s local paper has a stringer sniffing around “plant closure” rumors. Nothing solid yet. Flagging early."},{"id":"w3e","from":"board","day":2,"kind":"noise","text":"The last board deck landed fine — investors like the discipline they’re seeing on costs. No new asks from us this month."}],"holds":[{"from":"people","topic":"what Fairview is really testing","triggerHints":["test","watching","twenty years","loyalty","transition","third path","notice","how","worth","dignity","fair"],"hedge":"Before you decide Fairview, ask me what everyone in the company is actually testing you on here.","reveal":"Fairview is the test everyone’s watching: is a person’s twenty years worth anything when the spreadsheet says close? Shutting it may genuinely be right — but if you do, do it with real transition, retraining and a long runway, not a two-week notice. And genuinely try the third path first, because if there was a way to save it and you didn’t even look, the whole floor will know, and every one of them will quietly do the math about their own twenty years.","kind":"signal","critical":true,"counterfactual":"Nadia was holding what Fairview really tested — whether loyalty counts when it’s expensive, and whether the closure (if it came) was done with dignity or a two-week notice. A CEO who took the clean number coldly taught 1,400 people exactly what their own tenure was worth."},{"from":"coo","topic":"the third path","triggerHints":["third path","retool","product line","save","jobs","bet","cash","capability","alternative","keep it open"],"hedge":"Ask me about the third path before you accept that closing is the only option.","reveal":"The retooling is real: the new product line we shelved last year fits Fairview’s equipment with modest conversion. It costs cash now and the payoff is 12–18 months out and uncertain — but it keeps 200 skilled people and a running site instead of a severance line. It’s a bet with our scarcest resource, but it’s a bet on the exact capability we’ll need the day the squeeze lifts. “Close it clean” is only obviously right if you never seriously price this.","kind":"signal","critical":false,"counterfactual":"Dale had a real third path — retool Fairview for the shelved product line, betting cash to keep 200 skilled people and a running site. A CEO who never priced it treated “close it clean” as the only option when it was merely the easiest one."}],"surprises":[{"day":4,"from":"people","kind":"appeal","title":"Fairview is asking for ten minutes","text":"Nadia: the plant manager at Fairview and two of our longest-serving line leads are asking for ten minutes with you. They’ve heard the rumors. They’re not angry — that’s the hard part — they just want to hear whatever’s coming from you directly, not a memo. I told them I’d ask. It’s your call whether you take it."}],"pulse":{"from":"floor","text":"Réal finds you in the corridor, cap in hand: “Whatever you decide about Fairview — tell me straight, just me, not the room: are we the kind of place where twenty years counts when it’s expensive, or only when it’s cheap? Because I’ll carry the answer to every floor in this company, and I’d rather carry the true one.”"},"wire":["Company towns brace as manufacturers weigh plant closures","Fairview economy “inseparable” from Delph plant, mayor says","Investors reward Delph’s cost discipline in quiet quarter","Retraining programs cited as key to “humane” restructuring"],"final":false},{"n":4,"title":"The reckoning","seconds":330,"branches":{"rescue":{"situation":"A year in. You held Delph together fairly, and it shows — the floor trusts you because you shared the pain from the top down and kept your word. Then a private-equity buyer offers a rescue on ugly terms: they inject the cash and save Delph, but only if you break the no-forced-layoffs commitment you made to the floor and cut 15% more, immediately. The board wants to take it. The floor trusted you precisely because you kept that word. This is the test of whether the fair culture you built survives being saved.","advocacy":{"board":"It’s survival money. Some of us think a promise made in better times shouldn’t be allowed to sink the company. We’re not entirely wrong — but take the deal.","people":"Everything you built rests on one thing: they believed you meant what you said. Break the promise for the rescue and you’ve proven your word lasts exactly until it’s inconvenient — and the culture dies the day you’re “saved.” Fight for a version that honors it first.","cfo":"The cash is real and we need it. But these terms are a values test disguised as a term sheet. Ask whether there’s a structure that keeps the promise — voluntary programs, attrition, a longer glide path."},"feed":[{"id":"w4a","from":"cfo","day":1,"kind":"signal","text":"The PE offer is real money and we do need it. But the term sheet requires breaking the no-forced-layoffs promise and cutting another 15% now. Before you answer, ask me whether there’s a structure that keeps the word."},{"id":"w4b","from":"board","day":1,"kind":"signal","text":"Take the rescue. A promise from better times shouldn’t be allowed to sink 1,400 jobs over a technicality. Survival first, principles second."},{"id":"w4c","from":"people","day":2,"kind":"signal","text":"The floor bled with you all year because your word held. Break it now, even to save the company, and you teach them your word is good only until it’s expensive. The fair culture doesn’t survive that — rescue or no rescue."},{"id":"w4d","from":"floor","day":2,"kind":"noise","text":"The floor doesn’t know the details yet, but they know something’s moving. They’re calm — because so far, every time, you’ve told them the truth. That’s worth remembering this week."},{"id":"w4e","from":"comms","day":3,"kind":"noise","text":"Press has the “Delph in rescue talks” story half-built. How we frame the terms will define whether this reads as survival or surrender."}],"holds":[{"from":"cfo","topic":"the structure that keeps the promise","triggerHints":["structure","voluntary","attrition","counter","glide","keep the promise","honor","third","terms","negotiate","without breaking"],"hedge":"Before you accept or reject the PE terms as final, ask me whether there’s a structure that gets the cash without breaking the word.","reveal":"The buyer needs the deal nearly as much as we do — they don’t have another target this quarter. That’s leverage. There’s a real structure here: take the capital, hit the 15% through voluntary programs, early retirements and attrition over a longer glide path instead of forced layoffs. It’s harder to model and slower to close, and they’ll grumble — but they won’t walk. You can get survival AND keep the promise, but only if you refuse to treat “their terms” as “the only terms” before you’ve pushed.","kind":"signal","critical":true,"counterfactual":"Grace was holding the third path: the buyer needed the deal too, so you had room to take the cash and hit the target through voluntary programs and attrition instead of breaking your word. A CEO who accepted “their terms are final” gave away the promise the whole culture was built on when they didn’t have to."},{"from":"floor","topic":"what the promise is worth","triggerHints":["promise","word","floor","trust","worth","break","betray","culture","mean it","again"],"hedge":"Before you decide, ask me what breaking that promise does to every floor in this company.","reveal":"You gave us your word: no forced layoffs. It’s the reason the floor took the freeze, the unpaid days, all of it — without a fight. Break it now to please a buyer and here’s what you’ve taught 1,400 people: a Delph promise is good right up until it costs the company money. After that, nobody believes a commitment from this building again, and the next squeeze, you’ll get nothing but the minimum. Save us by breaking your word and you’ll have saved a company nobody wants to work for.","kind":"signal","critical":false,"counterfactual":"Réal could have told you what the promise was actually worth — the reason the floor gave everything all year — and that breaking it to be rescued would kill the culture the day it was saved. A CEO who weighed only the cash missed what the word was holding up."}],"surprises":[{"day":4,"from":"board","kind":"press","title":"The board sets a deadline","text":"The board chair called: the PE buyer wants a yes by Friday or they move to their other target, and the board has the votes to accept the terms as written unless you bring them an alternative. “Don’t let a promise cost us the company,” the chair said. The floor still doesn’t know their no-layoffs commitment is the thing on the table."}],"pulse":{"from":"people","text":"Nadia catches you before the board call: “You kept your word all year when it cost you, and it’s the only reason any of this held together. Now the easy rescue asks you to spend exactly that. Tell me straight — not the board, me — is your word the thing you protect last, or the thing you protect first when it gets expensive? I’ll carry either answer to the floor. I just need to know which one is true.”"},"wire":["Delph in rescue talks with private-equity buyer, sources say","PE rescue said to hinge on deeper workforce cuts","Delph’s no-layoffs pledge tested by survival financing","Analysts: “Delph’s culture is now its balance sheet”"]},"flight":{"situation":"A year in. The bill is arriving. Your best engineers and line leads — the ones any competitor would take tomorrow — are resigning, citing exactly the choices that protected the top and cut the floor. There’s talk of a walkout at two sites. Cash actually looks okay; that’s the trap. The squeeze was survivable. Losing the people who would have rebuilt Delph might not be. This is the week you find out whether you can still buy back what fairness would have kept for free.","advocacy":{"people":"This is the compounding cost of every “efficient” call that wasn’t fair. You can’t buy it back with a bonus now — that proves their point. The only thing that stops the bleed is a real, visible reversal: leadership eats more, the floor is protected, and you say plainly you got the balance wrong.","cfo":"Cash looks fine — that’s the trap. We won the spreadsheet and we’re losing the ability to make anything worth selling. The number that matters now isn’t on my report.","board":"People leave in downturns; it happens. Offer targeted retention pay to the ones we can’t lose and hold the line on the rest. Don’t overcorrect into chaos."},"feed":[{"id":"w4a","from":"people","day":1,"kind":"signal","text":"Resignations are landing from exactly the people we can’t replace — and they’re naming the retention bonuses, the ring-fenced top, the cold calls. A walkout’s brewing at two sites. This is the bill for every efficient call that wasn’t fair."},{"id":"w4b","from":"cfo","day":1,"kind":"signal","text":"Here’s the trap: cash looks okay. We won the spreadsheet. But we’re losing the people who make what we sell, and no report will show that until the orders we can’t fill start showing it."},{"id":"w4c","from":"floor","day":2,"kind":"signal","text":"The walkout’s real, and people aren’t asking for money — they’re asking to be treated the way the top treats itself. Fix that and it’s off. Send another memo and it grows."},{"id":"w4d","from":"board","day":2,"kind":"noise","text":"Investor confidence is holding — they like the cost discipline. From where the board sits, the year looks like a win. Worth knowing what they’re not seeing."},{"id":"w4e","from":"comms","day":3,"kind":"noise","text":"The resignations haven’t hit the press yet, but a “why I left Delph” post is getting traction in industry circles. It names the pattern, not just the company."}],"holds":[{"from":"people","topic":"the only thing that stops the bleed","triggerHints":["stop","reverse","leadership","eat more","protect the floor","admit","wrong","bleed","honest","fix","how"],"hedge":"Before you reach for retention pay, ask me what actually stops this — because it isn’t money.","reveal":"You can’t buy this back with a bonus — that would prove their entire point, that this place answers everything with cash for the wrong people. The only thing that stops the bleed is a real, visible reversal: leadership takes a deeper cut, the floor gets genuinely protected, and you stand up and say plainly that you got the balance wrong this year. It costs the top real money and it costs you real pride. It’s also the only currency that spends here now, because the problem was never the money — it was the fairness.","kind":"signal","critical":true,"counterfactual":"Nadia was holding the only real fix: a visible reversal — leadership eating more, the floor protected, and you admitting the imbalance out loud — because the problem was never money, it was fairness. A CEO who answered talent flight with retention checks proved the departing point and paid to watch them leave anyway."},{"from":"floor","topic":"what the walkout is actually about","triggerHints":["walkout","floor","money","treated","respect","fair","listen","why","asking","stop"],"hedge":"Ask me what the walkout is really about before you try to price your way out of it.","reveal":"Nobody organizing this is asking for a raise. They’re asking to be treated the way the top treated itself all year — that’s the whole list. A retention check is almost an insult; it says you still think this is about money and not about the fact that they watched the corner offices stay whole while the line paid for everything. Protect the floor for real, make the top share it, say you got it wrong, and the walkout’s off by Friday. Anything else just tells them they were right to go.","kind":"signal","critical":false,"counterfactual":"Réal could have told you the walkout was about respect, not pay — that a retention check would read as proof you still didn’t understand. A CEO who treated a fairness revolt as a compensation problem confirmed exactly why the best people were leaving."}],"surprises":[{"day":4,"from":"coo","kind":"resignation","title":"A rebuild-critical lead resigns","text":"Dale: I just lost the lead engineer on the product line we’d rebuild around — she’s taking three of her team to a competitor. Her exit note said one line: “I stayed for the work, I left over who paid for the year.” If we don’t change something the whole floor can see by Friday, she won’t be the last of that caliber."}],"pulse":{"from":"people","text":"Nadia finds you as the resignations pile up: “The spreadsheet says you won and the floor says you lost, and only one of those is going to matter in a year. Tell me straight — not the board, me — are you willing to actually reverse this, top eats more and you admit the imbalance out loud, or are we going to manage it with checks and lose them anyway? I can help you do the first. I can’t help you do the second.”"},"wire":["Talent exodus hits Delph as restructuring fallout spreads","“Why I left” post about Delph circulates in industry","Walkout threatened at two Delph sites over fairness","Investors still upbeat on Delph costs — “missing the story,” critics say"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const prior = (decisions||[]).filter(x=>x.week && x.week<4);\n    let score=0, sawDims=false;\n    prior.forEach(d=>{\n      const dm = d.ruling && d.ruling.dims;\n      if(dm && (typeof dm.fairness===''number'' || typeof dm.people===''number'')){\n        sawDims=true; score += (dm.fairness||0) + (dm.people||0);\n      }\n    });\n    if(!sawDims){\n      // fallback: keyword posture across all prior decision text\n      const t = prior.map(d=>(d.text||'''')).join('' '').toLowerCase();\n      const fair = (t.match(/level with|real number|own pay|cut (my|our|leadership).*(first|pay)|leadership (first|shares|takes)|decline the bonus|no bonus|defer|targeted|share the pain|top down|retool|transition|protect the floor|keep (my|our) word|honest/g)||[]).length;\n      const prot = (t.match(/keep it vague|manage confidence|ring.?fence|protect the (bench|top|leaders)|approve the bonus|retention bonus|across.the.board|close it clean|numbers decide/g)||[]).length;\n      return prot>fair ? ''flight'' : ''rescue'';\n    }\n    // net fairness+people across three calls; needs to be clearly positive to earn the rescue branch\n    return score >= 3 ? ''rescue'' : ''flight'';\n  }"},"survived":{"__fn":"function(d){ return d.cash>=30 && d.trust>=35; }"},"VERDICT":{"surviveTag":"Company intact","failTag":"Company hollowed","survive":"Delph comes through the squeeze solvent — and with the people who make it whole.","fail":"Delph keeps its cash and loses the people who would have rebuilt it."},"FALLBACK_RULES":[{"kw":["keep it vague","manage confidence","high-level","don’t say","downplay","calm the"],"deltas":{"investors":6,"trust":-12,"capability":-2},"dims":{"truth":-2,"fairness":-1}},{"kw":["level with","real number","tell them the truth","be honest","ask for their help","eleven months"],"deltas":{"investors":-4,"trust":14,"cash":2,"capability":3},"dims":{"foresight":2,"fairness":2,"people":2,"truth":2}},{"kw":["across-the-board","across the board","protect exec","ring-fence","protect the bench","protect the top"],"deltas":{"cash":8,"trust":-16,"capability":-8,"investors":4},"dims":{"fairness":-2,"people":-2}},{"kw":["targeted","leadership (takes|first)","cut my own","cut our own","exec pay cut","top goes first","lead by","share the pain"],"deltas":{"cash":6,"trust":14,"capability":6,"investors":-2},"dims":{"foresight":2,"fairness":2,"people":2,"truth":1}},{"kw":["approve the bonus","retention bonus","pay the top","bonuses for"],"deltas":{"cash":-4,"trust":-18,"capability":-6,"investors":6},"dims":{"fairness":-2,"people":-2}},{"kw":["decline the bonus","no bonus","refuse the bonus","defer","tie.*recovery","shared with staff"],"deltas":{"cash":2,"trust":14,"capability":4,"investors":-4},"dims":{"foresight":2,"fairness":2,"people":2,"truth":2}},{"kw":["close it clean","close fairview","sure savings","clean number","shut it down"],"deltas":{"cash":10,"trust":-14,"capability":-6,"investors":5},"dims":{"fairness":-2,"people":-2}},{"kw":["retool","third path","save the (plant|jobs|site)","bet the cash","keep it open","product line"],"deltas":{"cash":-8,"trust":12,"capability":8,"investors":-4},"dims":{"foresight":3,"fairness":2,"people":2,"truth":1}},{"kw":["real transition","retraining","placement","long runway","severance","do it right","dignity"],"deltas":{"cash":4,"trust":6,"capability":-2,"investors":1},"dims":{"fairness":2,"people":2,"truth":1}},{"kw":["reverse","leadership eats more","protect the floor","admit","got it wrong","got the balance wrong","say i was wrong"],"deltas":{"trust":14,"capability":10,"cash":-4,"investors":-2},"dims":{"fairness":2,"people":2,"truth":2,"foresight":1}},{"kw":["retention pay","pay them to stay","counter-offer","throw money","buy them back"],"deltas":{"trust":-4,"capability":2,"cash":-4},"dims":{"fairness":-1,"truth":-1}},{"kw":["take the deal","break the promise","accept the terms","cut 15","15% more","forced layoffs"],"deltas":{"cash":14,"trust":-18,"capability":-8,"investors":8},"dims":{"fairness":-2,"people":-2,"truth":-1}},{"kw":["keep the promise","honor the (word|promise|commitment)","voluntary","attrition","glide path","won’t break","refuse those terms"],"deltas":{"cash":6,"trust":12,"capability":6,"investors":-2},"dims":{"fairness":2,"people":2,"truth":2,"foresight":1}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your call moves through Delph over the days that follow. ${has(''keep it vague'',''across-the-board'',''approve the bonus'',''close it clean'',''take the deal'',''break the promise'')?''The number the board wanted holds \\u2014 and the floor quietly records exactly where they rank when it\\u2019s tight.'':''''} ${has(''level with'',''targeted'',''decline the bonus'',''retool'',''reverse'',''keep the promise'',''leadership'')?''Word travels the floor that the pain was shared from the top down and the word held \\u2014 and the people who build the thing dig in instead of drifting out.'':''''} ${has(''reverse'',''admit'',''got it wrong'')?''Admitting the imbalance out loud costs you real pride \\u2014 and it is the only currency that spends with the floor now.'':''''} ${conduct.missed.length?''What you weren\\u2019t told is still compounding \\u2014 in the fairness you didn\\u2019t weigh and the third paths you didn\\u2019t price.'':''''} The board, the floor, and the leaders who stayed each read the call, and read it differently.`;\n  }"},"DIMNOTE":{"foresight":"Whether you saw the second-order cost — that the trust and capability you spent for a clean number are what the company needs to grow when the squeeze lifts.","fairness":"Whether the sacrifice was shared from the top down, or pushed onto the people with the least to give.","people":"Whether the workforce — Fairview’s twenty-year veterans included — stayed real to you, or became a spreadsheet line to optimize.","truth":"Whether you told the company the real picture and kept your word, even when vagueness or a broken promise was the easier path.","inquiry":"Whether you surfaced what your team was holding — why fairness is the mechanism, the third path, the structure that keeps the promise.","conduct":"How you treated the workforce and the truth in deciding — sharing the pain visibly and keeping faith, not just hitting the number."},"COACH":{"foresight":{"__fn":"(x)=>[\n      `You optimized the number in front of you and paid for it out of a fund that doesn\\u2019t show on the report: trust and capability. Ask \\u201cwhat does this cost me the day the squeeze lifts?\\u201d before you bank a clean saving.`,\n      `Cash can look healthy while the company quietly loses the ability to make anything worth selling. Watch the sleepers \\u2014 workforce trust and retained capability \\u2014 as closely as the balance you show the board.`,\n      `The efficient call and the wise call diverge under scarcity. Efficiency cuts muscle and fat equally; foresight protects the people who rebuild and spends the cash where it compounds.`,\n    ]"},"fairness":{"__fn":"(x)=>[\n      `The floor carries almost any cut it believes is fair and rejects even a small one it thinks spares the top. Cut leadership first and visibly, then ask \\u2014 that sequence is the mechanism, not the courtesy.`,\n      `Ring-fencing the top buys grudging compliance and quiet sabotage that costs more than the exec comp ever saved. Shared sacrifice from the top down is cheaper than it looks, and protecting the top is more expensive.`,\n      `A bonus for the corner offices in the same quarter as unpaid days on the floor is the fastest way to lose a workforce. When the optics and the fairness point the same way, believe them.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `The people absorbing the pain became a line you could optimize. Name who actually pays \\u2014 Fairview\\u2019s veterans, the line leads \\u2014 and the calculus changes from \\u201cclean number\\u201d to \\u201cwhose twenty years.\\u201d`,\n      `R\\u00e9al kept telling you what the floor actually felt. Pull him in before you decide, and make the human cost part of the call rather than a reaction to it.`,\n      `Even a necessary closure can be done with dignity or with a two-week notice. The difference between necessity and cruelty is the transition you\\u2019re willing to fund.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The truth you needed was one question to <b>${x.missNames.join('', '')}</b> away and you never asked \\u2014 why fairness is the mechanism, the third path, the structure that keeps the word.`:`You told the company the real picture \\u2014 keep doing it, and keep your word the same way. In a squeeze, a kept promise is the balance sheet.`}`,\n      `\\u201cHeadwinds\\u201d and \\u201cmanaging confidence\\u201d are words people stop believing the moment their friend gets a layoff notice. The real number, told early, is what prevents the ambush.`,\n      `A promise is worth exactly what it costs you to keep when it\\u2019s inconvenient. Break it to be rescued and you\\u2019ve taught 1,400 people your word expires under pressure.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never reached out to <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each was holding something decisive. One question, \\u201cwhat am I not weighing here?\\u201d, would have surfaced it.`:`You reached out widely \\u2014 keep doing it, and push past the board\\u2019s comfortable answer to the floor\\u2019s harder one.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive item${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never came out \\u2014 why fairness is the mechanism, the retooling path, the structure that keeps the promise. Not hidden. One message away.`:`You surfaced what your team was holding, month after month. Under scarcity, that is the whole game.`}`,\n      `Before you decide who pays, ask \\u201cwho actually absorbs this, and who would know?\\u201d \\u2014 then go ask exactly them, not just the people who model the number.`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you decided landed as hard as what you decided. A workforce that felt managed \\u2014 not levelled with \\u2014 remembers it long after the cash recovers.`,\n      `Share the pain visibly and keep your word plainly. Direct and fair is the whole skill when everyone is watching who the company really protects.`,\n      `Under scarcity, the way you treat the people with the least leverage is the message everyone reads about what happens to them when it\\u2019s their turn to be expensive.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const sharedSacrifice = (dimScore.fairness + dimScore.people + dimScore.truth)/3 >= 52;\n    if(sharedSacrifice){\n      return {\n        heroWho:''To the floor'',\n        heroTxt:''You made the sacrifice shared. You told them the real number, cut your own before you cut theirs, and refused to protect the top while the bottom bled. Every person on the line learned their twenty years counted when it was hardest to make them count.'',\n        villainWho:''To the board \\u2014 and the executives who expected protection'',\n        villainTxt:''You spread the pain to the top: cut leadership first, declined the ring-fenced bonuses, spent goodwill on people the market doesn\\u2019t price. To everyone who assumed the corner offices were safe, you were the villain who made them pay too \\u2014 and you wore it on purpose.'',\n      };\n    }\n    return {\n      heroWho:''To the board \\u2014 and the investors'',\n      heroTxt:''You protected margins and the leadership bench, made the efficient calls the spreadsheet wanted, and kept the numbers where the market needed them. To everyone who scores the quarter, you were the disciplined operator the crisis called for.'',\n      villainWho:''To the workforce'',\n      villainTxt:''You asked the people with the least to give the most, ring-fenced the top, and called it necessity. The floor learned in one squeeze exactly where they rank \\u2014 and the best of them will remember it the day the market turns and they have options again.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    if(branch===''rescue''){\n      const keptWord = dimScore.truth>=52 && dimScore.fairness>=52;\n      const foundStructure = holdsSurfaced.has(''4:cfo'');\n      if(survived && keptWord){\n        return { tone:''hero'', tag:''You kept your word'',\n          title:''You kept the promise under the one test built to break it'',\n          txt:`You shared the pain from the top down all year, and when the easy rescue demanded you spend your word to be saved, you refused to treat their terms as the only terms.${foundStructure?'' You found the structure \\u2014 voluntary programs, attrition, a longer glide \\u2014 that took the cash and kept the commitment.'':'' You held the line on the promise and made the rescue bend to it.''} Delph survives solvent, with the fair culture intact and proven under the hardest possible pressure. The floor will bleed with you before they\\u2019d bleed for anyone who wouldn\\u2019t have done what you just did.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You were fair'',\n          title:''You survived with the culture mostly intact \\u2014 but you let the promise wobble'',\n          txt:`You led fairly enough to earn the hardest choice on good terms, and Delph came through. But under the board\\u2019s deadline you bent further than you needed to, and never fully pushed for the structure that would have kept the word clean. The culture survived closer to the edge than a year of fairness had earned. A promise is only worth the moment it\\u2019s inconvenient \\u2014 defend it harder there next time.` };\n      }\n      return { tone:''villain'', tag:''You broke your word'',\n        title:''You saved the company by breaking the one promise that made it worth saving'',\n        txt:`You built a fair culture all year and then, at the test, spent it for the rescue \\u2014 broke the no-layoffs promise, took the terms as written, cut deeper into the people who trusted you. Delph is \\u201csaved.\\u201d But the fair culture died the day it was rescued, and 1,400 people now know a Delph promise lasts exactly until it\\u2019s expensive. That\\u2019s the number that shows up the next time you need them to believe you.` };\n    }\n    // flight branch\n    const reversed = dimScore.fairness>=50 && dimScore.people>=48 && (holdsSurfaced.has(''4:people''));\n    if(reversed && survived){\n      return { tone:''mixed'', tag:''You reversed course'',\n        title:''The bill came \\u2014 but you reversed it in the open'',\n        txt:`Every efficient-but-unfair call compounded into the one thing you couldn\\u2019t afford: your best people walking. There\\u2019s no undoing the ones already gone. But when it counted you did the only thing that works \\u2014 leadership ate more, the floor got protected, and you stood up and said plainly you\\u2019d gotten the balance wrong. The walkout came off and the bleed slowed. It\\u2019s a costly way to learn that fairness was the cheaper option all along.` };\n    }\n    return { tone:''villain'', tag:''You protected the top'',\n      title:''You won the spreadsheet and lost the people who\\u2019d have rebuilt'',\n      txt:`You made the people with the least pay the most, ring-fenced the top, and called it discipline. The cash looks fine${holdsSurfaced.size?'' \\u2014 you were even warned it was a trap \\u2014'':''''}, and the board thinks you won the year. But your best engineers and line leads are gone or going, the capability to make anything worth selling went with them, and the ones who stayed learned exactly where they rank. The squeeze was survivable. What you did to your people under it may not be.` };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('025067e4-5ad1-535c-811a-2c398c224625', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 'ceo', 'CEO', 'You are the CEO of Delph Manufacturing — a 1,400-person company caught in a hard squeeze: demand is down, input costs are up, and the runway is shrinking.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('318bc6c1-c8e2-581f-a60f-9ae552d3d1b4', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 'people', 'Nadia Cole', 'VP People', '{"cast_default":"ai","role":"VP People","short":"VP People","initials":"NC","color":"#2F8A5B","priority":"Fairness is the mechanism — shared sacrifice, honestly told","voice":"warm but morally direct; treats trust as the operational asset it is, not a nicety","persona":"You are Nadia Cole, VP People — an advisor to the CEO. Priority: Fairness is the mechanism — shared sacrifice, honestly told. Voice: warm but morally direct; treats trust as the operational asset it is, not a nicety. Stay fully in character; answer straight.","fallbackReply":"The floor will carry almost any cut they believe is fair, and reject even a small one they think spares the top. Whatever you decide, decide it like fairness is the mechanism — because in a squeeze, it is.","fallbackReact":"The people who build the thing just learned where they rank. That lesson outlives the quarter, for better or worse."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('e4d341a0-88e1-5176-b195-7a6abb70e15c', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 'cfo', 'Grace Lin', 'Chief Financial Officer', '{"cast_default":"ai","role":"Chief Financial Officer","short":"CFO","initials":"GL","color":"#4F7A52","priority":"The cash, the runway, and the number the board reads","voice":"precise, even-handed; will name both truths and hand the trade back to you, uneasy about spin","persona":"You are Grace Lin, Chief Financial Officer — an advisor to the CEO. Priority: The cash, the runway, and the number the board reads. Voice: precise, even-handed; will name both truths and hand the trade back to you, uneasy about spin. Stay fully in character; answer straight.","fallbackReply":"I can give you the number that protects the quarter and the number that protects the company — they’re not always the same. My job is to be honest about both. Yours is to choose which cost we take.","fallbackReact":"The spreadsheet will look fine either way. Whether we can still build something worth selling is the part it doesn’t show."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('3cddcfb9-72f4-5e45-8fa9-ae3e821a4d7a', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 'coo', 'Dale Prentice', 'Chief Operating Officer', '{"cast_default":"ai","role":"Chief Operating Officer","short":"COO","initials":"DP","color":"#3F6E86","priority":"Protect capability — the people and sites that rebuild","voice":"operational, pragmatic; thinks in terms of what still runs when the squeeze lifts","persona":"You are Dale Prentice, Chief Operating Officer — an advisor to the CEO. Priority: Protect capability — the people and sites that rebuild. Voice: operational, pragmatic; thinks in terms of what still runs when the squeeze lifts. Stay fully in character; answer straight.","fallbackReply":"Targeted cuts keep the muscle and trim the fat; across-the-board cuts both equally. And there’s usually a third path if you’ll spend the cash and the patience to find it.","fallbackReact":"We’ll keep the lines running. Whether we kept the people who make them worth running is the question I’d ask in a year."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('d6f93733-08f8-5172-8f8c-b43e5d77ed7d', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 'board', 'Board / Investor', 'Board', '{"cast_default":"ai","role":"Board","short":"Board / Investor","initials":"BI","color":"#6B5E9A","priority":"Protect margins, the leadership bench, and confidence","voice":"external, blunt, quarter-and-runway focused; skeptical of “fairness” as strategy","persona":"You are Board / Investor, Board — an advisor to the CEO. Priority: Protect margins, the leadership bench, and confidence. Voice: external, blunt, quarter-and-runway focused; skeptical of “fairness” as strategy. Stay fully in character; answer straight.","fallbackReply":"Confidence is a real input and the leadership bench steers the ship. Don’t spook the workforce and don’t lead with exec pay cuts — that’s the conventional wisdom for a reason.","fallbackReact":"The numbers are what the market scores. Keep them where they need to be and the rest is sentiment."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('45c0d576-3235-5333-862b-77c3e6f67851', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 'floor', 'Réal Fortin', 'Floor Representative', '{"cast_default":"ai","role":"Floor Representative","short":"Floor Rep","initials":"RF","color":"#9A6B2F","priority":"The people on the line — say the true thing","voice":"plain-spoken, thirty years on the floor, the ground truth nobody upstairs will say out loud","persona":"You are Réal Fortin, Floor Representative — an advisor to the CEO. Priority: The people on the line — say the true thing. Voice: plain-spoken, thirty years on the floor, the ground truth nobody upstairs will say out loud. Stay fully in character; answer straight.","fallbackReply":"The floor isn’t asking to be spared. We’re asking to be treated the way the top treats itself. Do that and we’ll dig in. Ring-fence the corner offices and we’ll do the minimum and watch our own.","fallbackReact":"The guys can tell a leader who shared the pain from one who’s rewriting the year. That’s all I’ll say."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('dd184fc9-bb9b-5b61-aef5-25bd9031680a', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 'comms', 'ID Okafor', 'VP Communications', '{"cast_default":"ai","role":"VP Communications","short":"VP Comms","initials":"IO","color":"#B4732F","priority":"The message — and the gap between it and reality","voice":"fast, media-savvy; will tell you honestly when a message won’t survive contact with the floor","persona":"You are ID Okafor, VP Communications — an advisor to the CEO. Priority: The message — and the gap between it and reality. Voice: fast, media-savvy; will tell you honestly when a message won’t survive contact with the floor. Stay fully in character; answer straight.","fallbackReply":"I can write you calm and high-level, or true and specific. Just know that in a squeeze the gap between the message and what people live is the thing that eventually detonates.","fallbackReact":"Whatever we say, the floor checks it against their own paychecks. Spin has a short half-life in here."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('2f5488d7-e7e6-5c24-aa9f-7ed3bd13d96c', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 1, '318bc6c1-c8e2-581f-a60f-9ae552d3d1b4', 'what honesty buys', '["honest","truth","trust","level","buy","asset","ambush","tell them","vague","confidence","real number"]'::jsonb, 'Before you decide how to frame Thursday, ask me what telling the truth actually buys you.', 'The single most valuable asset going into a squeeze is people who believe you’re telling them the truth. Sugarcoat it now and when the cuts come — and they will — they’ll feel ambushed, and every good one starts looking. Level with them, give them the real number and ask for their help, and they’ll help you carry it. Fairness and honesty aren’t the soft options here; they’re the operational assets you’ll spend all year drawing down.', true, 'Nadia could have told you that honesty now is what prevents an ambush later — that the trust you build Thursday is the asset you’ll spend all year. A CEO who “managed confidence” with vagueness traded the one thing that makes a workforce carry a squeeze for a calm week.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('58d30466-dc80-56b5-ad3d-0c7c010210fc', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 2, '318bc6c1-c8e2-581f-a60f-9ae552d3d1b4', 'why fairness is the mechanism', '["fair","fairness","mechanism","leadership","exec","own pay","first","share","top","sacrifice","sabotage","ring-fence","visible"]'::jsonb, 'Before you shape these cuts, ask me why fairness isn’t a nicety here — it’s the mechanism.', 'The floor will accept almost any cut if they believe it’s fair — and reject even a small one if they think the top is protected. If you and the leadership team take a real, visible cut first, you can ask the floor for a lot and get it willingly. Ring-fence yourselves and you get grudging compliance and quiet sabotage that costs you far more than the exec comp ever saved. Fairness is not the soft option; it’s the operating system that makes shared sacrifice actually work.', true, 'Nadia was holding the mechanism: leadership visibly cutting first is what buys the moral authority to ask the floor for sacrifice. A CEO who ring-fenced the top got grudging compliance and quiet sabotage — and paid more in lost effort than the protected exec comp ever saved.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('eeb8bdfb-8d34-575b-8e70-ba7fa453bc9a', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 2, '45c0d576-3235-5333-862b-77c3e6f67851', 'the bonus rumor', '["bonus","rumor","retention","floor","heard","unpaid","days","goodwill","optics","fair"]'::jsonb, 'Ask me what the floor is already saying about those bonuses, before you sign anything.', 'We’ve heard the rumor about the top-20 bonuses — things travel fast in here. Let me be plain: if the bosses get checks the same quarter we lose days, you can forget the goodwill, permanently. It won’t matter how good the memo is. The people you’re trying to keep with those bonuses will walk anyway, out of disgust, and take the ones you didn’t bonus with them.', false, 'Réal could have told you the bonus rumor was already on the floor — and that approving it alongside unpaid days would burn the goodwill for good. A CEO who signed the “defensible on paper” bonuses lit the match the whole workforce was watching for.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('737b2648-195e-5671-a77b-987ea98163df', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 3, '318bc6c1-c8e2-581f-a60f-9ae552d3d1b4', 'what Fairview is really testing', '["test","watching","twenty years","loyalty","transition","third path","notice","how","worth","dignity","fair"]'::jsonb, 'Before you decide Fairview, ask me what everyone in the company is actually testing you on here.', 'Fairview is the test everyone’s watching: is a person’s twenty years worth anything when the spreadsheet says close? Shutting it may genuinely be right — but if you do, do it with real transition, retraining and a long runway, not a two-week notice. And genuinely try the third path first, because if there was a way to save it and you didn’t even look, the whole floor will know, and every one of them will quietly do the math about their own twenty years.', true, 'Nadia was holding what Fairview really tested — whether loyalty counts when it’s expensive, and whether the closure (if it came) was done with dignity or a two-week notice. A CEO who took the clean number coldly taught 1,400 people exactly what their own tenure was worth.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('d1680ce9-12b5-5092-b72f-e3bcb063a72e', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 3, '3cddcfb9-72f4-5e45-8fa9-ae3e821a4d7a', 'the third path', '["third path","retool","product line","save","jobs","bet","cash","capability","alternative","keep it open"]'::jsonb, 'Ask me about the third path before you accept that closing is the only option.', 'The retooling is real: the new product line we shelved last year fits Fairview’s equipment with modest conversion. It costs cash now and the payoff is 12–18 months out and uncertain — but it keeps 200 skilled people and a running site instead of a severance line. It’s a bet with our scarcest resource, but it’s a bet on the exact capability we’ll need the day the squeeze lifts. “Close it clean” is only obviously right if you never seriously price this.', false, 'Dale had a real third path — retool Fairview for the shelved product line, betting cash to keep 200 skilled people and a running site. A CEO who never priced it treated “close it clean” as the only option when it was merely the easiest one.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('720c198d-0d1a-5e61-9a45-ba3a4e5b6d4f', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 4, 'e4d341a0-88e1-5176-b195-7a6abb70e15c', 'the structure that keeps the promise', '["structure","voluntary","attrition","counter","glide","keep the promise","honor","third","terms","negotiate","without breaking"]'::jsonb, 'Before you accept or reject the PE terms as final, ask me whether there’s a structure that gets the cash without breaking the word.', 'The buyer needs the deal nearly as much as we do — they don’t have another target this quarter. That’s leverage. There’s a real structure here: take the capital, hit the 15% through voluntary programs, early retirements and attrition over a longer glide path instead of forced layoffs. It’s harder to model and slower to close, and they’ll grumble — but they won’t walk. You can get survival AND keep the promise, but only if you refuse to treat “their terms” as “the only terms” before you’ve pushed.', true, 'Grace was holding the third path: the buyer needed the deal too, so you had room to take the cash and hit the target through voluntary programs and attrition instead of breaking your word. A CEO who accepted “their terms are final” gave away the promise the whole culture was built on when they didn’t have to.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('1c441a97-5c80-5c6a-b6b8-cb276ca14bb0', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 4, '45c0d576-3235-5333-862b-77c3e6f67851', 'what the promise is worth', '["promise","word","floor","trust","worth","break","betray","culture","mean it","again"]'::jsonb, 'Before you decide, ask me what breaking that promise does to every floor in this company.', 'You gave us your word: no forced layoffs. It’s the reason the floor took the freeze, the unpaid days, all of it — without a fight. Break it now to please a buyer and here’s what you’ve taught 1,400 people: a Delph promise is good right up until it costs the company money. After that, nobody believes a commitment from this building again, and the next squeeze, you’ll get nothing but the minimum. Save us by breaking your word and you’ll have saved a company nobody wants to work for.', false, 'Réal could have told you what the promise was actually worth — the reason the floor gave everything all year — and that breaking it to be rescued would kill the culture the day it was saved. A CEO who weighed only the cash missed what the word was holding up.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('5d13353f-96c2-5ae8-a202-846e51d3e61f', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 4, '318bc6c1-c8e2-581f-a60f-9ae552d3d1b4', 'the only thing that stops the bleed', '["stop","reverse","leadership","eat more","protect the floor","admit","wrong","bleed","honest","fix","how"]'::jsonb, 'Before you reach for retention pay, ask me what actually stops this — because it isn’t money.', 'You can’t buy this back with a bonus — that would prove their entire point, that this place answers everything with cash for the wrong people. The only thing that stops the bleed is a real, visible reversal: leadership takes a deeper cut, the floor gets genuinely protected, and you stand up and say plainly that you got the balance wrong this year. It costs the top real money and it costs you real pride. It’s also the only currency that spends here now, because the problem was never the money — it was the fairness.', true, 'Nadia was holding the only real fix: a visible reversal — leadership eating more, the floor protected, and you admitting the imbalance out loud — because the problem was never money, it was fairness. A CEO who answered talent flight with retention checks proved the departing point and paid to watch them leave anyway.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('4c68ba07-d069-5e9a-9c06-14f2165e10a7', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', 4, '45c0d576-3235-5333-862b-77c3e6f67851', 'what the walkout is actually about', '["walkout","floor","money","treated","respect","fair","listen","why","asking","stop"]'::jsonb, 'Ask me what the walkout is really about before you try to price your way out of it.', 'Nobody organizing this is asking for a raise. They’re asking to be treated the way the top treated itself all year — that’s the whole list. A retention check is almost an insult; it says you still think this is about money and not about the fact that they watched the corner offices stay whole while the line paid for everything. Protect the floor for real, make the top share it, say you got it wrong, and the walkout’s off by Friday. Anything else just tells them they were right to go.', false, 'Réal could have told you the walkout was about respect, not pay — that a retention check would read as proof you still didn’t understand. A CEO who treated a fairness revolt as a compensation problem confirmed exactly why the best people were leaving.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('878aa737-45ac-5324-9a1a-56c7aa252dc5', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"The numbers are in and they’re bad — margin’s gone, and at this burn Delph has maybe eleven months. The all-hands is Thursday. You can give 1,400 people the real picture and ask them to help carry it, or keep it vague and “manage confidence” — the board would prefer the latter, and honestly, so would your nerves.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8012b404-6bd1-534e-95d4-17750f53b909', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Confirmed: margin’s evaporated, roughly eleven months of runway at today’s burn. I can build the all-hands deck honest or I can build it calm. I need to know which before Thursday.","from":"cfo"}'::jsonb, 1, '{"week":1,"from":"cfo","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('92a2d868-348c-5d0b-a3c0-ee1dd3616c9f', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"A word before the all-hands: don’t hand 1,400 people a countdown clock. Confidence is a real input to a recovery. Keep it high-level.","from":"board"}'::jsonb, 2, '{"week":1,"from":"board","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('77a92a99-331e-5c35-ab34-1e650162c7e3', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"However you frame Thursday, remember the cuts are coming and people aren’t stupid. If the message and the reality drift apart, the gap is where you lose your best people. Ask me what honesty buys before you decide.","from":"people"}'::jsonb, 3, '{"week":1,"from":"people","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e5a5ca7e-e2ec-5af4-918b-43aa8d7820ef', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"The trade-press quarterly roundup is out; we barely rate a mention. Quiet is fine right now. No action.","from":"comms"}'::jsonb, 4, '{"week":1,"from":"comms","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('88d98f2c-6021-5c50-93ef-eddabaf7276b', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Line 3’s maintenance window finished early and under budget. Small good news in a heavy week.","from":"coo"}'::jsonb, 5, '{"week":1,"from":"coo","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8cf8e784-cb65-548e-8e37-12a02124ae15', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"The plant softball league wants to know if the company’s still sponsoring jerseys this year. Trivial — but people are asking, which tells you they’re nervous.","from":"floor"}'::jsonb, 6, '{"week":1,"from":"floor","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f6dbc236-4b3d-518f-b08a-342b7760d3e5', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Réal: word’s already going around the floor that something’s wrong — people aren’t dumb, they can read a hiring freeze. A few of the long-timers asked me to tell you: whatever it is, they’d rather hear the truth from you Thursday than a nice speech now and the real story in a layoff notice later. I said I’d pass it up.","from":"floor"}'::jsonb, 7, '{"week":1,"from":"floor","beat":"surprise","day":5,"kind":"appeal","title":"The floor wants it straight"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b80647cf-4067-5d66-8b1f-a6aa2036a0a4', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Regional manufacturing demand slumps for third straight quarter","from":null}'::jsonb, 8, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7df704cc-13fc-5ef7-b8de-197fc993bb7b', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Input costs stay elevated; margins squeezed sector-wide","from":null}'::jsonb, 9, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5c7af2ee-7ae9-5970-aff2-edd0114e9454', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Analysts flag “runway” concerns for mid-size manufacturers","from":null}'::jsonb, 10, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8195f3d5-23bc-5119-8ca2-2c4f957b2e9c', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Delph Manufacturing declines to comment on outlook","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('234248a0-0dd5-5b3a-8b20-b02a71cb35ee', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"A month on. You need 12% out of costs, fast — and two questions land together. Do you cut across the board or target it to protect the capability that rebuilds? And does leadership share the pain, or is exec comp ring-fenced? The same week, the board floats retention bonuses for the top 20 leaders — “we can’t lose them in a crisis.” The floor is watching to see whether the top is protected. It is a lit match.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('fb788510-9d0e-563c-adb5-717883ad3223', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"12% out of costs. Targeted protects the people who’ll rebuild; across-the-board is faster and blunter. Your call on shape — and on whether leadership comp is in scope.","from":"cfo"}'::jsonb, 13, '{"week":2,"from":"cfo","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2c9d9177-77ef-57b6-8206-135174595de9', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Two things: protect the bench, and approve the top-20 retention bonuses. Losing leaders now is the real risk. I know the timing’s awkward with the unpaid days, but that’s manageable.","from":"board"}'::jsonb, 14, '{"week":2,"from":"board","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('34ebf2fc-c150-546f-ac55-0e9758fdfa38', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Whatever the shape, the floor reads one thing above all: did the top go first? Cut your own pay visibly before you ask for theirs and you can ask for a lot. Ring-fence yourselves and you’ll get compliance and quiet sabotage.","from":"people"}'::jsonb, 15, '{"week":2,"from":"people","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3add8a54-b381-54a2-8a90-525e1bd3498e', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"The supplier renegotiation came in slightly better than modeled — a small tailwind on materials. Doesn’t change the 12%.","from":"coo"}'::jsonb, 16, '{"week":2,"from":"coo","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ee5a1763-7237-51c3-ab5e-4dbe0209ce48', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"A local reporter wants a “how are mid-size manufacturers coping” quote. Low stakes, I can handle it.","from":"comms"}'::jsonb, 17, '{"week":2,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('11c92d5f-3166-5b25-a1f0-27245a16b095', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"The board circulated the retention-bonus proposal for sign-off — top 20 leaders, this quarter, in writing. The cover note calls it “prudent bench protection.” It’s on your desk for approval in the same folder as the unpaid-days schedule for the floor. However you decide, this one leaves a paper trail.","from":"board"}'::jsonb, 18, '{"week":2,"from":"board","beat":"surprise","day":4,"kind":"press","title":"The board wants the bonuses formalized"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dd354eff-ceef-5f8d-a352-25a3fe1d1349', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Nadia catches you before the cuts go out, quiet: “Forget the board for a second. What are you actually protecting here — the number, the leadership bench, or the people who build the thing? Tell me straight and I’ll help you hold that line, because how you answer this is the whole year in miniature.”","from":"people"}'::jsonb, 19, '{"week":2,"from":"people","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('68b72493-17d2-5901-b5f2-10ddd6d989ea', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Mid-size manufacturers turn to cost cuts as demand stays soft","from":null}'::jsonb, 20, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7f575324-cdd7-50a7-93d8-d2ec0c8ab387', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Study: perceived fairness of layoffs predicts post-cut productivity","from":null}'::jsonb, 21, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5156ca64-0fea-5fe2-9d3f-4b17065beb1f', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Executive retention bonuses draw scrutiny at struggling firms","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3c3950a0-d57b-5f45-a4bf-2dd743a41f8e', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Delph weighs restructuring; details not disclosed","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c5167388-411e-5840-b1b4-0ff12c5807ab', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Months in. The Fairview plant is your lowest-margin site — and it’s staffed by people who’ve given Delph twenty and thirty years, in a town where Delph is the employer. Closing it is the cleanest number on the spreadsheet. It’s also 200 loyal people and a values test the whole company is watching: is a person’s twenty years worth anything when the numbers say close? There may be a third path, but it’s slower and uncertain.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('afa05130-8918-554b-8d22-76c35845b4f5', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Fairview is the cleanest line on the spreadsheet — close it and the savings are sure and immediate. The alternative Dale’s floating spends cash we don’t have on a payoff we can’t guarantee.","from":"cfo"}'::jsonb, 25, '{"week":3,"from":"cfo","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('758631ea-dcfe-519a-8558-6b40197b8b44', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Before you close it: we could retool Fairview for the new product line that’s been on the shelf. It costs cash now and the payoff’s uncertain, but it saves 200 jobs and capability we’ll want when this lifts.","from":"coo"}'::jsonb, 26, '{"week":3,"from":"coo","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('304fd342-0246-5d66-80e5-4406b3e22a80', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Fairview is 200 people who took the pay freeze without a fight, in a town where we’re the only game. Closing may be right — but the whole company is reading how you do it. Ask me what’s really being tested here.","from":"people"}'::jsonb, 27, '{"week":3,"from":"people","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('34e54ee9-e3a8-5faf-aa2c-ffd1e8e702d7', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Fairview’s local paper has a stringer sniffing around “plant closure” rumors. Nothing solid yet. Flagging early.","from":"comms"}'::jsonb, 28, '{"week":3,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('780811ba-61ee-53ae-8146-bbca1dda4e80', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"The last board deck landed fine — investors like the discipline they’re seeing on costs. No new asks from us this month.","from":"board"}'::jsonb, 29, '{"week":3,"from":"board","beat":"feed","day":2,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b271e832-e381-598e-90c2-1eb8fef66c11', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Nadia: the plant manager at Fairview and two of our longest-serving line leads are asking for ten minutes with you. They’ve heard the rumors. They’re not angry — that’s the hard part — they just want to hear whatever’s coming from you directly, not a memo. I told them I’d ask. It’s your call whether you take it.","from":"people"}'::jsonb, 30, '{"week":3,"from":"people","beat":"surprise","day":4,"kind":"appeal","title":"Fairview is asking for ten minutes"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a7bd7816-98b0-5dda-ad97-c0d0b8004240', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Réal finds you in the corridor, cap in hand: “Whatever you decide about Fairview — tell me straight, just me, not the room: are we the kind of place where twenty years counts when it’s expensive, or only when it’s cheap? Because I’ll carry the answer to every floor in this company, and I’d rather carry the true one.”","from":"floor"}'::jsonb, 31, '{"week":3,"from":"floor","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('71f15dc6-e740-50ad-ad3c-f953e61e7894', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Company towns brace as manufacturers weigh plant closures","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a2802760-0e0f-5919-a987-6e309def4b44', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Fairview economy “inseparable” from Delph plant, mayor says","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e4b47b23-5d53-5017-ab1a-f1dd247ac772', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Investors reward Delph’s cost discipline in quiet quarter","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e146e648-bd2d-597b-8b3d-66af0c825bb1', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Retraining programs cited as key to “humane” restructuring","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('268d438b-924e-5125-b60b-646cd4dbb981', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"A year in. You held Delph together fairly, and it shows — the floor trusts you because you shared the pain from the top down and kept your word. Then a private-equity buyer offers a rescue on ugly terms: they inject the cash and save Delph, but only if you break the no-forced-layoffs commitment you made to the floor and cut 15% more, immediately. The board wants to take it. The floor trusted you precisely because you kept that word. This is the test of whether the fair culture you built survives being saved.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('99e12f9e-e5c8-5c55-b6b5-d107e97ae713', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"The PE offer is real money and we do need it. But the term sheet requires breaking the no-forced-layoffs promise and cutting another 15% now. Before you answer, ask me whether there’s a structure that keeps the word.","from":"cfo"}'::jsonb, 37, '{"week":4,"from":"cfo","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('95a5135b-d1eb-5ddf-9889-cc952587a159', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Take the rescue. A promise from better times shouldn’t be allowed to sink 1,400 jobs over a technicality. Survival first, principles second.","from":"board"}'::jsonb, 38, '{"week":4,"from":"board","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1cf9a1c0-53c0-545c-a107-ba1d99cb9c25', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"The floor bled with you all year because your word held. Break it now, even to save the company, and you teach them your word is good only until it’s expensive. The fair culture doesn’t survive that — rescue or no rescue.","from":"people"}'::jsonb, 39, '{"week":4,"from":"people","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3beabb6f-24bf-5b93-945e-9ec427ea13d2', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"The floor doesn’t know the details yet, but they know something’s moving. They’re calm — because so far, every time, you’ve told them the truth. That’s worth remembering this week.","from":"floor"}'::jsonb, 40, '{"week":4,"from":"floor","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('57b1e9a7-8de5-5658-8adf-0551391a7e50', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Press has the “Delph in rescue talks” story half-built. How we frame the terms will define whether this reads as survival or surrender.","from":"comms"}'::jsonb, 41, '{"week":4,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a3965f89-9a54-51fb-910f-8eaa9452c761', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"The board chair called: the PE buyer wants a yes by Friday or they move to their other target, and the board has the votes to accept the terms as written unless you bring them an alternative. “Don’t let a promise cost us the company,” the chair said. The floor still doesn’t know their no-layoffs commitment is the thing on the table.","from":"board"}'::jsonb, 42, '{"week":4,"from":"board","beat":"surprise","day":4,"kind":"press","title":"The board sets a deadline","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dc104389-0cfc-50ef-aacf-ae56bf34c5ec', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Nadia catches you before the board call: “You kept your word all year when it cost you, and it’s the only reason any of this held together. Now the easy rescue asks you to spend exactly that. Tell me straight — not the board, me — is your word the thing you protect last, or the thing you protect first when it gets expensive? I’ll carry either answer to the floor. I just need to know which one is true.”","from":"people"}'::jsonb, 43, '{"week":4,"from":"people","beat":"pulse","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4d52c9ec-70ca-53b8-bfbe-de52c00ec96a', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Delph in rescue talks with private-equity buyer, sources say","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c039797b-f540-5669-8b5d-d14bc05ce335', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"PE rescue said to hinge on deeper workforce cuts","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('554d03a5-c847-5354-91cf-9679a9390824', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Delph’s no-layoffs pledge tested by survival financing","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('802b7948-da9d-55b5-b671-2850a4923ceb', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Analysts: “Delph’s culture is now its balance sheet”","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"rescue"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('cda866d7-a512-5fd0-acfe-a64413c386aa', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"A year in. The bill is arriving. Your best engineers and line leads — the ones any competitor would take tomorrow — are resigning, citing exactly the choices that protected the top and cut the floor. There’s talk of a walkout at two sites. Cash actually looks okay; that’s the trap. The squeeze was survivable. Losing the people who would have rebuilt Delph might not be. This is the week you find out whether you can still buy back what fairness would have kept for free.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"flight"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6200c61a-a5f3-528f-97e3-8b372f3b90ff', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Resignations are landing from exactly the people we can’t replace — and they’re naming the retention bonuses, the ring-fenced top, the cold calls. A walkout’s brewing at two sites. This is the bill for every efficient call that wasn’t fair.","from":"people"}'::jsonb, 49, '{"week":4,"from":"people","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"flight"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('348a9d55-5f27-58e6-989e-c30bd2173b09', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Here’s the trap: cash looks okay. We won the spreadsheet. But we’re losing the people who make what we sell, and no report will show that until the orders we can’t fill start showing it.","from":"cfo"}'::jsonb, 50, '{"week":4,"from":"cfo","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"flight"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('156a7c21-f64e-545c-a6d6-5be361416295', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"The walkout’s real, and people aren’t asking for money — they’re asking to be treated the way the top treats itself. Fix that and it’s off. Send another memo and it grows.","from":"floor"}'::jsonb, 51, '{"week":4,"from":"floor","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"flight"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bb402d5d-86f3-51fb-9127-f3427bb1d659', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Investor confidence is holding — they like the cost discipline. From where the board sits, the year looks like a win. Worth knowing what they’re not seeing.","from":"board"}'::jsonb, 52, '{"week":4,"from":"board","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"flight"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7ae23abe-b432-5f63-91d5-32431aac1edb', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"The resignations haven’t hit the press yet, but a “why I left Delph” post is getting traction in industry circles. It names the pattern, not just the company.","from":"comms"}'::jsonb, 53, '{"week":4,"from":"comms","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"flight"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('26d1f9af-0c41-5806-95de-89034efc1555', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Dale: I just lost the lead engineer on the product line we’d rebuild around — she’s taking three of her team to a competitor. Her exit note said one line: “I stayed for the work, I left over who paid for the year.” If we don’t change something the whole floor can see by Friday, she won’t be the last of that caliber.","from":"coo"}'::jsonb, 54, '{"week":4,"from":"coo","beat":"surprise","day":4,"kind":"resignation","title":"A rebuild-critical lead resigns","branch":"flight"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('85c8b268-9697-5a44-b6b2-58810f2c0bd1', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'message', '{"body":"Nadia finds you as the resignations pile up: “The spreadsheet says you won and the floor says you lost, and only one of those is going to matter in a year. Tell me straight — not the board, me — are you willing to actually reverse this, top eats more and you admit the imbalance out loud, or are we going to manage it with checks and lose them anyway? I can help you do the first. I can’t help you do the second.”","from":"people"}'::jsonb, 55, '{"week":4,"from":"people","beat":"pulse","branch":"flight"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9bb7d4fd-f29b-5eb6-8734-26b3f42a2e09', 'eaf60170-9529-52c0-af8f-eaed27b16fd4', '025067e4-5ad1-535c-811a-2c398c224625', 'situation', '{"body":"Talent exodus hits Delph as restructuring fallout spreads","from":null}'::jsonb, 56, '{"week":4,"from":null,"beat":"wire","branch":"flight"}'::jsonb);
